// src/pages/ProductDetails.js
import { useParams } from "react-router-dom";
import { useState } from "react";
import products from "../data/ProductData";

function ProductDetails() {
  const { id } = useParams();
  const product = products.find((p) => p.id === parseInt(id));

  // State for main image (default = product.image)
  const [mainImage, setMainImage] = useState(product?.image);

  if (!product)
    return <h2 className="text-center mt-10">Product Not Found</h2>;

  return (
    <div className="max-w-6xl mx-auto p-8 grid md:grid-cols-2 gap-10">
      {/* Left - Product Image */}
      <div className="flex flex-col items-center">
        {/* Main Image Box */}
        <div className="w-[350px] h-[350px] flex items-center justify-center bg-gray-100 rounded-lg shadow">
          <img
            src={mainImage}
            alt={product.name}
            className="max-w-full max-h-full object-contain"
          />
        </div>

        {/* Thumbnails */}
        <div className="flex gap-2 mt-4">
          {[product.image, ...(product.images || [])].map((img, idx) => (
            <img
              key={idx}
              src={img}
              alt={'thumb-${idx}'}
              onClick={() => setMainImage(img)}
              className={`w-16 h-16 object-contain border rounded cursor-pointer ${
                mainImage === img ? "border-orange-500" : "border-gray-300"
              }`}
            />
          ))}
        </div>
      </div>

      {/* Right - Product Info */}
      <div>
        <h1 className="text-3xl font-bold">{product.name}</h1>

        {/* Rating */}
        <div className="flex items-center gap-2 mt-2">
          <span className="text-orange-500 text-lg">★★★★☆</span>
          <p className="text-gray-600">({product.rating})</p>
        </div>

        {/* Description */}
        <p className="mt-4 text-gray-700 leading-relaxed">
          {product.description}
        </p>

        {/* Price */}
        <div className="mt-4">
          <span className="text-2xl font-bold text-gray-900">
            ₹{product.price}
          </span>
          {product.oldPrice && (
            <span className="line-through text-gray-500 ml-3">
              ₹{product.oldPrice}
            </span>
          )}
        </div>

        {/* Extra Info */}
        <div className="mt-6 space-y-2 text-gray-700">
          <p>
            <span className="font-semibold">Brand:</span> {product.brand}
          </p>
          <p>
            <span className="font-semibold">Color:</span> {product.color}
          </p>
          <p>
            <span className="font-semibold">Category:</span> {product.category}
          </p>
        </div>

        {/* Buttons */}
        <div className="flex gap-4 mt-8">
          <button className="flex-1 bg-gray-200 text-gray-800 py-3 rounded hover:bg-gray-300">
            Add to Cart
          </button>
          <button className="flex-1 bg-orange-500 text-white py-3 rounded hover:bg-orange-600">
            Buy now
          </button>
        </div>
      </div>
    </div>
  );
}

export default ProductDetails;
